
import { defineComponent, computed, onMounted } from 'vue';
import { useStore } from 'vuex';
import AppControls from '@/components/AppControls.vue';
import { attributeIcons, perks } from '@/data/brothersData';
import AppDeck from '@/components/AppDeck.vue';
import AppCard from '@/components/AppCard.vue';

export default defineComponent({
	components: { AppControls, AppDeck, AppCard },
	name: 'BrothersPlanner',
	setup() {
		//Internal
		const store = useStore();
		let changeTimer = undefined as number | undefined;
		const attributeKeys = Object.keys(attributeIcons);
		//Ref
		//Computed
		//Methods
		//#region Classes
		const addClass = () => {
			store.commit('brothers/addNewClass');
		};
		const moveClass = (index: number, newIndex: number) => {
			clearTimeout(changeTimer);
			changeTimer = setTimeout(() => {
				store.dispatch('brothers/moveClass', { index, newIndex });
			}, 500);
		};
		const removeClass = (index: number) => {
			store.commit('brothers/removeClass', { index });
		};
		const changeClassProp = (
			index: number,
			prop: string,
			value: string | number
		) => {
			clearTimeout(changeTimer);
			let timeout = 0;
			if (prop === 'name' || prop === 'link' || prop === 'needed') {
				timeout = 500;
			}
			changeTimer = setTimeout(() => {
				store.commit('brothers/changeClassProp', { index, prop, value });
			}, timeout);
		};
		const changeClassPropAttr = (
			index: number,
			prop: string,
			attr: string,
			value: string | number
		) => {
			clearTimeout(changeTimer);
			let timeout = 0;
			if (prop === 'attr') {
				timeout = 500;
			}
			changeTimer = setTimeout(() => {
				store.commit('brothers/changeClassPropAttr', {
					index,
					prop,
					attr,
					value,
				});
			}, timeout);
		};
		const pasteClassLink = (index: number) => {
			navigator.clipboard.readText().then((value) => {
				store.commit('brothers/changeClassProp', {
					index,
					prop: 'link',
					value,
				});
			});
		};
		//#endregion
		//#region Brothers
		const add = () => {
			store.commit('brothers/addNewItem');
		};
		const save = () => {
			store.dispatch('brothers/saveToStorage');
		};
		const reset = () => {
			store.dispatch('brothers/clearStorage');
		};
		const moveItem = (index: number, newIndex: number) => {
			clearTimeout(changeTimer);
			changeTimer = setTimeout(() => {
				store.dispatch('brothers/moveItem', { index, newIndex });
			}, 500);
		};
		const removeItem = (index: number) => {
			store.commit('brothers/removeItem', { index });
		};
		const changeProp = (
			index: number,
			prop: string,
			value: string | number
		) => {
			clearTimeout(changeTimer);
			let timeout = 0;
			if (prop === 'name' || prop === 'level') {
				timeout = 500;
			}
			changeTimer = setTimeout(() => {
				store.commit('brothers/changeProp', { index, prop, value });
			}, timeout);
		};
		const changePropAttr = (
			index: number,
			prop: string,
			attr: string,
			value: string | number
		) => {
			clearTimeout(changeTimer);
			let timeout = 0;
			if (prop === 'attr') {
				timeout = 500;
			}
			changeTimer = setTimeout(() => {
				store.commit('brothers/changePropAttr', { index, prop, attr, value });
			}, timeout);
		};
		const cycleTalent = (index: number, attr: string) => {
			store.commit('brothers/cycleTalent', { index, attr });
		};
		const pastePerkLink = (index: number) => {
			navigator.clipboard.readText().then((value) => {
				store.commit('brothers/changeProp', {
					index,
					prop: 'perksLink',
					value,
				});
			});
		};
		//#endregion
		//Hooks
		onMounted(() => {
			store.dispatch('brothers/loadFromStorage');
		});
		return {
			store,
			attributeKeys,
			attributeIcons,
			perks,
			addClass,
			moveClass,
			removeClass,
			changeClassProp,
			changeClassPropAttr,
			pasteClassLink,
			add,
			save,
			reset,
			moveItem,
			removeItem,
			changeProp,
			changePropAttr,
			cycleTalent,
			pastePerkLink,
		};
	},
});
